df_biz = pd.DataFrame(biz)
df_rev = pd.DataFrame(rev)

# parse hours: stored as string representation of list
weekdays = {'Monday','Tuesday','Wednesday','Thursday','Friday'}

_time_re = re.compile(r'^(?P<h>\d{1,2})(?::(?P<m>\d{2}))?\s*(?P<ampm>AM|PM)$', re.I)

def to_minutes(t):
    t=t.strip()
    m=_time_re.match(t)
    if not m:
        return None
    h=int(m.group('h'))
    mi=int(m.group('m') or 0)
    ampm=m.group('ampm').upper()
    if ampm=='AM':
        if h==12: h=0
    else:
        if h!=12: h+=12
    return h*60+mi

# determine if open after 6pm on at least one weekday

def open_after_6(hours_val):
    if hours_val is None or (isinstance(hours_val,float) and pd.isna(hours_val)):
        return False
    s = hours_val
    if isinstance(s, list):
        arr = s
    else:
        try:
            arr = ast.literal_eval(s)
        except Exception:
            return False
    for day, hrs in arr:
        if day not in weekdays:
            continue
        if not isinstance(hrs,str):
            continue
        hrs=hrs.strip()
        if hrs.lower()=='closed':
            continue
        if 'open 24 hours' in hrs.lower():
            return True
        # handle possible multiple intervals separated by comma
        parts=[p.strip() for p in hrs.split(',')]
        for part in parts:
            if '–' in part:
                a,b=[x.strip() for x in part.split('–',1)]
            elif '-' in part:
                a,b=[x.strip() for x in part.split('-',1)]
            else:
                continue
            end = to_minutes(b)
            if end is None:
                continue
            if end>18*60:
                return True
    return False


df_biz['open_after_6_weekday'] = df_biz['hours'].apply(open_after_6)

# merge ratings
# coerce numeric
for c in ['avg_rating','review_count']:
    df_rev[c] = pd.to_numeric(df_rev[c], errors='coerce')

df = df_biz.merge(df_rev, on='gmap_id', how='inner')

# filter
df_f = df[df['open_after_6_weekday'] & df['avg_rating'].notna()]

# choose top 5 by avg_rating desc, tie-break by review_count desc
out = df_f.sort_values(['avg_rating','review_count'], ascending=[False,False]).head(5)

# format operating hours as readable lines

def format_hours(hours_val):
    try:
        arr = ast.literal_eval(hours_val) if isinstance(hours_val,str) else hours_val
    except Exception:
        arr = None
    if not arr:
        return None
    return '; '.join([f"{d}: {h}" for d,h in arr])

out_res = []
for _,r in out.iterrows():
    out_res.append({
        'name': r['name'],
        'operating_hours': format_hours(r['hours']),
        'avg_rating': float(r['avg_rating'])
    })

result = json.dumps(out_res, ensure_ascii=False)
print('__RESULT__:')
print(result)

